async function main() {
  const raw = String($env.TWENTY_INTERNAL_BASE || '');
  const base = raw.endsWith('/') ? raw.slice(0, -1) : raw;
  const token = $env.TWENTY_API_KEY;
  if (!base || !token) throw new Error('TWENTY_INTERNAL_BASE and TWENTY_API_KEY must be set');
  const b = $input.first().json;
  const p = b.payload || {};
  const email = (p.email || '').trim();
  const firstName = (p.firstName || '').trim() || 'Lead';
  const lastName = (p.lastName || '').trim() || 'Contact';
  const phone = (p.phone || '').trim();
  if (!email) return [];
  const utmLine = [
    p.utm_source && 'utm_source=' + p.utm_source,
    p.utm_medium && 'utm_medium=' + p.utm_medium,
    p.utm_campaign && 'utm_campaign=' + p.utm_campaign,
    p.utm_content && 'utm_content=' + p.utm_content,
  ].filter(Boolean).join(' | ');
  const jobLine = utmLine ? 'Funnel | ' + utmLine : 'Funnel (no UTM)';
  const authHeaders = { Authorization: 'Bearer ' + token, 'Content-Type': 'application/json' };
  const filter = 'emails.primaryEmail[eq]:' + email;
  const url = base + '/rest/people?filter=' + encodeURIComponent(filter) + '&limit=1';
  const getRes = await this.helpers.httpRequest({ method: 'GET', url, headers: authHeaders, json: true });
  const people = getRes && getRes.data && Array.isArray(getRes.data.people) ? getRes.data.people : [];
  const existing = people[0] || null;
  if (existing && existing.id) {
    const prior = String(existing.jobTitle || '').trim();
    const mergedJobTitle = (prior ? prior + ' | ' + jobLine : jobLine).slice(0, 500);
    const patchBody = { jobTitle: mergedJobTitle };
    if (phone && !(existing.phones && existing.phones.primaryPhoneNumber)) {
      patchBody.phones = {
        primaryPhoneNumber: phone,
        primaryPhoneCountryCode: '',
        primaryPhoneCallingCode: '',
        additionalPhones: null,
      };
    }
    const patchRes = await this.helpers.httpRequest({
      method: 'PATCH',
      url: base + '/rest/people/' + existing.id,
      headers: authHeaders,
      body: patchBody,
      json: true,
    });
    return [{ json: { ok: true, action: 'updated', personId: existing.id, twenty: patchRes } }];
  }
  const twentyBody = {
    name: { firstName, lastName },
    emails: { primaryEmail: email, additionalEmails: null },
    jobTitle: jobLine,
  };
  if (phone) {
    twentyBody.phones = {
      primaryPhoneNumber: phone,
      primaryPhoneCountryCode: '',
      primaryPhoneCallingCode: '',
      additionalPhones: null,
    };
  }
  const postRes = await this.helpers.httpRequest({
    method: 'POST',
    url: base + '/rest/people',
    headers: authHeaders,
    body: twentyBody,
    json: true,
  });
  return [{ json: { ok: true, action: 'created', twenty: postRes } }];
}
return await main.call(this);
